mapper.select:
SELECT COUNT(*) AS total
FROM homework h


        AND h.creator = #{userId}


        AND h.class_id = #{classId}

SELECT c.class_name AS className, u.user_name AS userName, co.course_name AS courseName,
FROM homework h LEFT JOIN class c ON c.id = h.class_id LEFT JOIN course co ON co.id = c.course_id LEFT JOIN `user` u ON u.id = h.creator
AND h.creator = #{userId}
AND h.class_id = #{classId}
ORDER BY h.id DESC LIMIT #{page},#{pageSize}

SELECT COUNT(*) AS total FROM homework h LEFT JOIN user_do_homework udh ON h.id = udh.homework_id
AND udh.user_id IS NULL
AND h.class_id = #{classId}
ORDER BY h.id DESC LIMIT #{page},#{pageSize}
